from __future__ import annotations
import argparse from datetime import date, datetime from pathlib import Path
import pandas as pd
try: from .config import AppConfig, load_config from .extract import fetch_records, paginate_records, load_records_from_file, records_to_dataframe, save_raw_payload from .charts import generate_all_charts from .analytics import ( build_daily_issue_trend, build_daily_run_metrics, build_monthly_trend, build_rolling_daily_metrics, build_violation_time_series, build_weekday_trend, ) from .alerts import build_alert_log_rows, evaluate_significant_changes, send_webhook_alerts from .readme_sync import upsert_latest_run_section from .report import ( build_summary_dataframe, build_top_counties, build_top_violation_types, calculate_kpis, compare_snapshots, render_markdown_report, ) from .transform import transform_violations from .validate import run_data_quality_checks except ImportError: # pragma: no cover from config import AppConfig, load_config from extract import fetch_records, paginate_records, load_records_from_file, records_to_dataframe, save_raw_payload from charts import generate_all_charts from analytics import ( build_daily_issue_trend, build_daily_run_metrics, build_monthly_trend, build_rolling_daily_metrics, build_violation_time_series, build_weekday_trend, ) from alerts import build_alert_log_rows, evaluate_significant_changes, send_webhook_alerts from readme_sync import upsert_latest_run_section from report import ( build_summary_dataframe, build_top_counties, build_top_violation_types, calculate_kpis, compare_snapshots, render_markdown_report, ) from transform import transform_violations from validate import run_data_quality_checks
def parse_args() -> argparse.Namespace: parser = argparse.ArgumentParser(description="Generate the daily NYC open parking violations report.") parser.add_argument("--limit", type=int, default=None, help="Override the number of API rows to request.") parser.add_argument("--open-only", action="store_true", help="Only include violations with open balances.") parser.add_argument("--camera-only", action="store_true", help="Only include camera violations.") parser.add_argument("--input-file", type=str, default=None, help="Optional local JSON payload for offline runs.") parser.add_argument( "--report-date", type=str, default=None, help="Optional report date override in YYYY-MM-DD format.", ) parser.add_argument("--paginate", action="store_true", help="Paginate through all available records.") return parser.parse_args()
def resolve_report_date(value: str | None) -> date: if value is None: return date.today() return datetime.strptime(value, "%Y-%m-%d").date()
def load_previous_snapshot(snapshot_path: Path) -> pd.DataFrame | None: if not snapshot_path.exists(): return None return pd.read_csv(snapshot_path, parse_dates=["issue_date", "report_date"])
def save_outputs( config: AppConfig, report_date: date, records: list[dict], transformed_df: pd.DataFrame, summary_df: pd.DataFrame, markdown_report: str, analytics_outputs: dict[str, pd.DataFrame], alert_log_df: pd.DataFrame, ) -> None: stamp = report_date.isoformat()
raw_path = config.raw_dir / f"violations_{stamp}.json" processed_history_path = config.history_dir / f"violations_{stamp}.csv" processed_history_parquet_path = config.history_dir / f"violations_{stamp}.parquet" latest_snapshot_path = config.processed_dir / "latest_snapshot.csv" latest_snapshot_parquet_path = config.processed_dir / "latest_snapshot.parquet" latest_summary_path = config.data_dir / "latest_summary.csv" latest_summary_parquet_path = config.data_dir / "latest_summary.parquet" latest_report_path = config.reports_dir / "daily_report.md" dated_report_path = config.reports_dir / f"daily_report_{stamp}.md" analytics_dir = config.analytics_dir analytics_dir.mkdir(parents=True, exist_ok=True)
save_raw_payload(records, raw_path) transformed_df.to_csv(processed_history_path, index=False) transformed_df.to_parquet(processed_history_parquet_path, index=False) transformed_df.to_csv(latest_snapshot_path, index=False) transformed_df.to_parquet(latest_snapshot_parquet_path, index=False) summary_df.to_csv(latest_summary_path, index=False) summary_df.to_parquet(latest_summary_parquet_path, index=False)
for name, analytics_df in analytics_outputs.items(): csv_path = analytics_dir / f"{name}.csv" parquet_path = analytics_dir / f"{name}.parquet" analytics_df.to_csv(csv_path, index=False) analytics_df.to_parquet(parquet_path, index=False)
if not alert_log_df.empty: latest_alerts_csv = analytics_dir / "alerts_log.csv" if latest_alerts_csv.exists(): existing = pd.read_csv(latest_alerts_csv) alert_log_df = pd.concat([existing, alert_log_df], ignore_index=True) alert_log_df.to_csv(latest_alerts_csv, index=False) alert_log_df.to_parquet(analytics_dir / "alerts_log.parquet", index=False)
latest_report_path.write_text(markdown_report, encoding="utf-8") dated_report_path.write_text(markdown_report, encoding="utf-8")
readme_path = config.data_dir.parent / "README.md" upsert_latest_run_section(readme_path, summary_df, latest_report_path)
def main() -> None: args = parse_args() config = load_config() report_date = resolve_report_date(args.report_date)
for directory in ( config.raw_dir, config.processed_dir, config.history_dir, config.analytics_dir, config.reports_dir, config.charts_dir, ): directory.mkdir(parents=True, exist_ok=True)
if args.input_file: records = load_records_from_file(args.input_file) else: if args.paginate: records = paginate_records( config=config, camera_only=args.camera_only, open_only=args.open_only, ) else: records = fetch_records( config=config, limit=args.limit, camera_only=args.camera_only, open_only=args.open_only, )
raw_df = records_to_dataframe(records) transformed_df = transform_violations(raw_df, report_date=report_date) quality_checks = run_data_quality_checks(transformed_df)
generate_all_charts(transformed_df, config.charts_dir)
previous_snapshot_path = config.processed_dir / "latest_snapshot.csv" previous_df = load_previous_snapshot(previous_snapshot_path)
kpis = calculate_kpis(transformed_df) diff_summary, day_over_day_changes = compare_snapshots(transformed_df, previous_df) top_violation_types = build_top_violation_types(transformed_df) top_counties = build_top_counties(transformed_df) summary_df = build_summary_dataframe(kpis, diff_summary, quality_checks, report_date.isoformat()) analytics_outputs = { "daily_issue_trend": build_daily_issue_trend(transformed_df), "weekday_trend": build_weekday_trend(transformed_df), "monthly_trend": build_monthly_trend(transformed_df), "rolling_daily_metrics": build_rolling_daily_metrics(transformed_df), "violation_time_series": build_violation_time_series(transformed_df), "daily_run_metrics": build_daily_run_metrics(transformed_df, report_date), }
alerts = evaluate_significant_changes( summary_df, pct_change_threshold=config.alert_pct_change_threshold, absolute_count_threshold=config.alert_absolute_count_threshold, ) alert_log_df = build_alert_log_rows(alerts, report_date.isoformat()) if config.alerts_enabled and config.alert_webhook_url and alerts: try: send_webhook_alerts(config.alert_webhook_url, alerts, report_date.isoformat()) except Exception as exc: # pragma: no cover print(f"Alert webhook failed: {exc}")
markdown_report = render_markdown_report( report_date=report_date.isoformat(), kpis=kpis, diff_summary=diff_summary, top_violation_types=top_violation_types, top_counties=top_counties, day_over_day_changes=day_over_day_changes, quality_checks=quality_checks, transformed_df=transformed_df, daily_trend_df=analytics_outputs["daily_issue_trend"], weekday_trend_df=analytics_outputs["weekday_trend"], monthly_trend_df=analytics_outputs["monthly_trend"], significant_alerts=alerts, )
save_outputs( config, report_date, records, transformed_df, summary_df, markdown_report, analytics_outputs, alert_log_df, )
print(f"Saved {len(transformed_df):,} transformed records.") print(f"Saved report to {config.reports_dir / 'daily_report.md'}") print(f"Saved summary to {config.data_dir / 'latest_summary.csv'}") print(f"Saved analytics outputs to {config.analytics_dir}") print(f"Generated charts in {config.charts_dir}") if alerts: print(f"Generated {len(alerts)} alert(s).")
if __name__ == "__main__": main()

from __future__ import annotations

from typing import Any

import pandas as pd



def format_currency(value: float) -> str:
    return f"${value:,.2f}"



def build_top_violation_types(df: pd.DataFrame, top_n: int = 10) -> pd.DataFrame:
    if df.empty:
        return pd.DataFrame(columns=["Rank", "Violation Type", "Count", "Amount Due"])

    summary = (
        df.groupby("violation", dropna=False)
        .agg(Count=("summons_number", "count"), Amount_Due=("amount_due", "sum"))
        .sort_values(["Count", "Amount_Due"], ascending=[False, False])
        .head(top_n)
        .reset_index()
    )
    summary.insert(0, "Rank", range(1, len(summary) + 1))
    summary = summary.rename(columns={"violation": "Violation Type", "Amount_Due": "Amount Due"})
    return summary



def build_top_counties(df: pd.DataFrame, top_n: int = 5) -> pd.DataFrame:
    if df.empty:
        return pd.DataFrame(columns=["Rank", "County", "Count", "Amount Due"])

    summary = (
        df.groupby("county", dropna=False)
        .agg(Count=("summons_number", "count"), Amount_Due=("amount_due", "sum"))
        .sort_values(["Amount_Due", "Count"], ascending=[False, False])
        .head(top_n)
        .reset_index()
    )
    summary.insert(0, "Rank", range(1, len(summary) + 1))
    summary = summary.rename(columns={"county": "County", "Amount_Due": "Amount Due"})
    return summary



def calculate_kpis(df: pd.DataFrame) -> dict[str, Any]:
    total_records = len(df)
    total_camera = int(df["is_camera_violation"].sum()) if "is_camera_violation" in df.columns else 0

    return {
        "total_records_pulled": total_records,
        "total_open_amount_due": float(df["amount_due"].sum()) if "amount_due" in df.columns else 0.0,
        "total_fine_amount": float(df["fine_amount"].sum()) if "fine_amount" in df.columns else 0.0,
        "total_penalty_amount": float(df["penalty_amount"].sum()) if "penalty_amount" in df.columns else 0.0,
        "total_interest_amount": float(df["interest_amount"].sum()) if "interest_amount" in df.columns else 0.0,
        "total_payment_amount": float(df["payment_amount"].sum()) if "payment_amount" in df.columns else 0.0,
        "total_camera_violations": total_camera,
        "total_non_camera_parking_violations": total_records - total_camera,
    }



def compare_snapshots(current_df: pd.DataFrame, previous_df: pd.DataFrame | None) -> tuple[dict[str, Any], pd.DataFrame]:
    if previous_df is None or previous_df.empty:
        diff_summary = {
            "new_records_pulled": int(len(current_df)),
            "resolved_or_missing_since_yesterday": 0,
            "net_record_change": int(len(current_df)),
            "previous_record_count": 0,
        }
        changes = (
            current_df.groupby("violation", dropna=False)
            .agg(current_count=("summons_number", "count"), current_amount_due=("amount_due", "sum"))
            .reset_index()
        )
        changes["previous_count"] = 0
        changes["previous_amount_due"] = 0.0
    else:
        current_keys = set(current_df["summons_number"].dropna().astype(str))
        previous_keys = set(previous_df["summons_number"].dropna().astype(str))
        diff_summary = {
            "new_records_pulled": len(current_keys - previous_keys),
            "resolved_or_missing_since_yesterday": len(previous_keys - current_keys),
            "net_record_change": len(current_df) - len(previous_df),
            "previous_record_count": len(previous_df),
        }

        current_grouped = (
            current_df.groupby("violation", dropna=False)
            .agg(current_count=("summons_number", "count"), current_amount_due=("amount_due", "sum"))
        )
        previous_grouped = (
            previous_df.groupby("violation", dropna=False)
            .agg(previous_count=("summons_number", "count"), previous_amount_due=("amount_due", "sum"))
        )
        changes = current_grouped.join(previous_grouped, how="outer").fillna(0).reset_index()

    changes["count_change"] = changes["current_count"] - changes["previous_count"]
    changes["amount_due_change"] = changes["current_amount_due"] - changes["previous_amount_due"]
    changes["abs_count_change"] = changes["count_change"].abs()
    changes = changes.sort_values(
        ["abs_count_change", "count_change", "amount_due_change"],
        ascending=[False, False, False],
    ).head(10)
    changes = changes.rename(
        columns={
            "violation": "Violation Type",
            "current_count": "Current Count",
            "previous_count": "Previous Count",
            "count_change": "Count Change",
            "current_amount_due": "Current Amount Due",
            "previous_amount_due": "Previous Amount Due",
            "amount_due_change": "Amount Due Change",
        }
    )
    changes = changes.drop(columns=["abs_count_change"])

    return diff_summary, changes.reset_index(drop=True)



def build_summary_dataframe(kpis: dict[str, Any], diff_summary: dict[str, Any], checks: list[dict[str, Any]], report_date: str) -> pd.DataFrame:
    summary = {
        "report_date": report_date,
        **kpis,
        **diff_summary,
        "checks_passed": sum(check["result"] == "PASS" for check in checks),
        "checks_failed": sum(check["result"] == "FAIL" for check in checks),
    }
    return pd.DataFrame([summary])


def build_borough_breakdown(df: pd.DataFrame, top_n: int = 10) -> pd.DataFrame:
    if df.empty:
        return pd.DataFrame(columns=["County", "Count", "Amount Due"])

    summary = (
        df.groupby("county", dropna=False)
        .agg(Count=("summons_number", "count"), Amount_Due=("amount_due", "sum"))
        .sort_values(["Amount_Due", "Count"], ascending=[False, False])
        .head(top_n)
        .reset_index()
    )
    summary = summary.rename(columns={"county": "County", "Amount_Due": "Amount Due"})
    return summary.reset_index(drop=True)


def build_agency_breakdown(df: pd.DataFrame, top_n: int = 10) -> pd.DataFrame:
    if df.empty:
        return pd.DataFrame(columns=["Issuing Agency", "Count", "Amount Due"])

    summary = (
        df.groupby("issuing_agency", dropna=False)
        .agg(Count=("summons_number", "count"), Amount_Due=("amount_due", "sum"))
        .sort_values(["Count", "Amount_Due"], ascending=[False, False])
        .head(top_n)
        .reset_index()
    )
    summary = summary.rename(columns={"issuing_agency": "Issuing Agency", "Amount_Due": "Amount Due"})
    return summary.reset_index(drop=True)



def _stringify(value: Any) -> str:
    if isinstance(value, float):
        return f"{value:,.2f}"
    return str(value)



def dataframe_to_markdown(df: pd.DataFrame) -> str:
    if df.empty:
        return "_No data available._"

    columns = list(df.columns)
    widths = []
    for column in columns:
        values = [_stringify(value) for value in df[column].tolist()]
        widths.append(max(len(str(column)), *(len(value) for value in values)))

    header = "| " + " | ".join(str(column).ljust(width) for column, width in zip(columns, widths)) + " |"
    separator = "| " + " | ".join("-" * width for width in widths) + " |"
    rows = []
    for _, row in df.iterrows():
        rows.append(
            "| "
            + " | ".join(_stringify(row[column]).ljust(width) for column, width in zip(columns, widths))
            + " |"
        )
    return "\n".join([header, separator, *rows])



def render_markdown_report(
    report_date: str,
    kpis: dict[str, Any],
    diff_summary: dict[str, Any],
    top_violation_types: pd.DataFrame,
    top_counties: pd.DataFrame,
    day_over_day_changes: pd.DataFrame,
    quality_checks: list[dict[str, Any]],
    transformed_df: pd.DataFrame | None = None,
    daily_trend_df: pd.DataFrame | None = None,
    weekday_trend_df: pd.DataFrame | None = None,
    monthly_trend_df: pd.DataFrame | None = None,
    significant_alerts: list[dict[str, Any]] | None = None,
) -> str:
    checks_df = pd.DataFrame(quality_checks)

    qa_note = (
        "The dataset refreshed successfully. No major data quality issues were detected in today's pull."
        if (checks_df["result"] == "PASS").all()
        else "One or more data quality checks failed. Review the details table below before publishing downstream outputs."
    )

    markdown = f"""# NYC Open Parking & Camera Violations Daily Report

Report Date: {report_date}

## Dashboard & Charts

![Top Violations](./charts/top_violations.png)
![Top Counties](./charts/top_counties.png)
![Top Agencies](./charts/top_agencies.png)
![Camera vs Parking](./charts/camera_vs_parking.png)

## Executive Summary

- Total Records Pulled: {kpis['total_records_pulled']:,}
- New Records Pulled Since Yesterday: {diff_summary['new_records_pulled']:,}
- Open Amount Due: {format_currency(kpis['total_open_amount_due'])}
- Total Fine Amount: {format_currency(kpis['total_fine_amount'])}
- Total Penalties: {format_currency(kpis['total_penalty_amount'])}
- Total Interest: {format_currency(kpis['total_interest_amount'])}
- Total Payments Recorded: {format_currency(kpis['total_payment_amount'])}
- Total Camera Violations: {kpis['total_camera_violations']:,}
- Total Non-Camera Parking Violations: {kpis['total_non_camera_parking_violations']:,}
- Previous Snapshot Record Count: {diff_summary['previous_record_count']:,}
- Resolved or Missing Since Yesterday: {diff_summary['resolved_or_missing_since_yesterday']:,}
- Net Record Change: {diff_summary['net_record_change']:,}

## Top Violation Types

{dataframe_to_markdown(top_violation_types)}

## Top 5 Counties by Amount Due

{dataframe_to_markdown(top_counties)}

## Borough & County Breakdown

{dataframe_to_markdown(build_borough_breakdown(transformed_df)) if transformed_df is not None and not transformed_df.empty else "_No data available._"}

