from __future__ import annotations

import pandas as pd

from src.alerts import build_alert_log_rows, evaluate_significant_changes


def test_alerts_trigger_on_large_change() -> None:
    summary_df = pd.DataFrame(
        [
            {
                "report_date": "2026-05-06",
                "total_records_pulled": 2000,
                "previous_record_count": 1000,
                "net_record_change": 1000,
            }
        ]
    )

    alerts = evaluate_significant_changes(summary_df, pct_change_threshold=20.0, absolute_count_threshold=500)
    assert len(alerts) >= 2

    log_df = build_alert_log_rows(alerts, "2026-05-06")
    assert not log_df.empty
    assert {"timestamp_utc", "report_date", "type", "severity", "message"}.issubset(log_df.columns)


def test_alerts_no_trigger_when_small_change() -> None:
    summary_df = pd.DataFrame(
        [
            {
                "report_date": "2026-05-06",
                "total_records_pulled": 1010,
                "previous_record_count": 1000,
                "net_record_change": 10,
            }
        ]
    )

    alerts = evaluate_significant_changes(summary_df, pct_change_threshold=50.0, absolute_count_threshold=5000)
    assert alerts == []

from __future__ import annotations
from src.extract import build_query_params, records_to_dataframe
REQUIRED_COLUMNS = { "summons_number", "issue_date", "violation", "fine_amount", "penalty_amount", "interest_amount", "payment_amount", "amount_due", "county", "issuing_agency", }
def test_sample_payload_contains_required_columns(sample_records: list[dict]) -> None: df = records_to_dataframe(sample_records) assert REQUIRED_COLUMNS.issubset(set(df.columns))
def test_build_query_params_for_open_camera_request() -> None: params = build_query_params(limit=1000, camera_only=True, open_only=True) assert params["$limit"] == 1000 assert params["$order"] == "issue_date DESC" assert "amount_due > 0" in params["$where"] assert "violation in(" in params["$where"]
